Implementasi Observer Pattern yang stabil dan aman untuk arsitektur aplikasi Anda. Kode ini mencakup penanganan exception untuk mencegah satu observer yang error menghancurkan seluruh proses notifikasi.

```python
from abc import ABC, abstractmethod
from typing import List, Any
import logging

# Konfigurasi Logging untuk Audit Trail
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')
logger = logging.getLogger(__name__)

class Observer(ABC):
    @abstractmethod
    def update(self, subject: 'Subject') -> None:
        pass

class Subject:
    def __init__(self):
        self._observers: List[Observer] = []
        self._state: Any = None

    def attach(self, observer: Observer) -> None:
        if observer not in self._observers:
            self._observers.append(observer)
            logger.info(f"Observer attached: {observer.__class__.__name__}")

    def detach(self, observer: Observer) -> None:
        try:
            self._observers.remove(observer)
            logger.info(f"Observer detached: {observer.__class__.__name__}")
        except ValueError:
            logger.warning(f"Observer not found: {observer.__class__.__name__}")

    def set_state(self, state: Any) -> None:
        self._state = state
        self.notify()

    def get_state(self) -> Any:
        return self._state

    def notify(self) -> None:
        """
        Keamanan: Wrap update dalam try-except. 
        Satu observer yang crash tidak boleh menghentikan notifikasi ke observer lain.
        """
        for observer in self._observers:
            try:
                observer.update(self)
            except Exception as e:
                logger.error(f"Observer {observer.__class__.__name__} failed: {str(e)}")
                # Lanjutkan ke observer berikutnya (Fail-safe)

# Implementasi Concrete Observer
class LogObserver(Observer):
    def update(self, subject: Subject) -> None:
        logger.info(f"LogObserver: State changed to {subject.get_state()}")

class SecurityAlertObserver(Observer):
    def update(self, subject: Subject) -> None:
        state = subject.get_state()
        # Contoh logika keamanan sederhana
        if isinstance(state, str) and "error" in state.lower():
            logger.critical(f"SecurityAlert: Potential issue detected -> {state}")

# Usage Example
if __name__ == "__main__":
    subject = Subject()

    log_obs = LogObserver()
    sec_obs = SecurityAlertObserver()

    subject.attach(log_obs)
    subject.attach(sec_obs)

    # Trigger update
    subject.set_state("System Operational")
    subject.set_state("Critical Error Detected")

    # Cleanup
    subject.detach(log_obs)
    subject.set_state("System Recovery")
```

### Catatan Teknis & Keamanan:

1.  **Isolasi Exception**: Metode `notify` dibungkus `try-except`. Ini wajib untuk mencegah *Denial of Service* internal jika salah satu observer memiliki bug atau sengaja dimanipulasi untuk throw exception.
2.  **Validasi Duplikasi**: `attach` mengecek keberadaan observer untuk mencegah redundansi memori dan eksekusi ganda.
3.  **Logging**: Semua aksi attach, detach, dan failure dicatat. Ini krusial untuk audit trail dan debugging produksi.
4.  **Type Hinting**: Menggunakan `typing` untuk memastikan integritas data dan memudahkan static analysis tools mendeteksi anomali kode.

Gunakan pola ini untuk sistem event logging, monitoring server, atau trigger keamanan pada aplikasi web Anda.

PERINGATAN KEAMANAN KRITIS: **Jangan pernah menggunakan `eval()`** untuk mengeksekusi input pengguna. Itu adalah celah keamanan fatal (Remote Code Execution/RCE) yang memungkinkan attacker mengambil alih server Anda.

Berikut adalah implementasi aman menggunakan modul `ast` (Abstract Syntax Tree) dengan whitelist operator. Hanya operasi matematika dasar yang diizinkan.

```python
import ast
import operator

class SafeMathEvaluator(ast.NodeVisitor):
    """Parser aman untuk ekspresi matematika sederhana."""

    ALLOWED_OPERATORS = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.Pow: operator.pow,
        ast.Mod: operator.mod,
        ast.USub: operator.neg,
        ast.UAdd: operator.pos,
    }

    def visit_BinOp(self, node):
        if type(node.op) not in self.ALLOWED_OPERATORS:
            raise ValueError(f"Operator tidak diizinkan: {type(node.op).__name__}")

        left = self.visit(node.left)
        right = self.visit(node.right)

        return self.ALLOWED_OPERATORS[type(node.op)](left, right)

    def visit_UnaryOp(self, node):
        if type(node.op) not in self.ALLOWED_OPERATORS:
            raise ValueError(f"Operator unary tidak diizinkan: {type(node.op).__name__}")

        operand = self.visit(node.operand)
        return self.ALLOWED_OPERATORS[type(node.op)](operand)

    def visit_Num(self, node):
        # Python < 3.8
        return node.n

    def visit_Constant(self, node):
        # Python >= 3.8
        if isinstance(node.value, (int, float)):
            return node.value
        raise ValueError("Hanya angka yang diizinkan")

    def generic_visit(self, node):
        # Blokir semua node lain (fungsi, variabel, import, dll)
        raise ValueError(f"Ekspresi tidak aman terdeteksi: {type(node).__name__}")

def evaluate_math_expression(expression: str) -> float:
    try:
        tree = ast.parse(expression, mode='eval')
        evaluator = SafeMathEvaluator()
        return evaluator.visit(tree.body)
    except Exception as e:
        raise ValueError(f"Input tidak valid atau tidak aman: {str(e)}")

# Contoh Penggunaan
if __name__ == "__main__":
    try:
        print(evaluate_math_expression("2 + 3 * (4 - 1)"))  # Output: 11.0
        print(evaluate_math_expression("__import__('os').system('ls')"))  # Raises ValueError
    except ValueError as e:
        print(f"Error: {e}")
```

### Analisis Teknis:
1.  **Mitigasi RCE:** Kode ini memblokir akses ke fungsi bawaan, import modul, atau variabel. Hanya literal angka dan operator matematika yang diproses.
2.  **AST Parsing:** Menggunakan `ast.parse` dengan mode `eval` untuk membongkar struktur kode tanpa menjalankannya langsung.
3.  **Whitelist Strict:** `generic_visit` memastikan jika ada node AST yang tidak didefinisikan secara eksplisit (seperti `ast.Call` untuk fungsi), eksekusi akan dihentikan.

Gunakan ini untuk production. Jangan kompromi keamanan server demi kepraktisan kode.

Berikut fungsi Python untuk membandingkan dua dictionary secara rekursif:

```python
def diff_dicts(dict1, dict2, path=""):
    """
    Membandingkan dua dictionary secara rekursif.
    Returns: list of differences found
    """
    differences = []

    # Cek key yang ada di dict1 tapi tidak di dict2
    for key in dict1.keys():
        current_path = f"{path}.{key}" if path else key

        if key not in dict2:
            differences.append({
                "type": "removed",
                "path": current_path,
                "value": dict1[key]
            })
        elif isinstance(dict1[key], dict) and isinstance(dict2[key], dict):
            # Rekursif untuk nested dict
            differences.extend(diff_dicts(dict1[key], dict2[key], current_path))
        elif dict1[key] != dict2[key]:
            differences.append({
                "type": "changed",
                "path": current_path,
                "old_value": dict1[key],
                "new_value": dict2[key]
            })

    # Cek key yang ada di dict2 tapi tidak di dict1
    for key in dict2.keys():
        current_path = f"{path}.{key}" if path else key

        if key not in dict1:
            differences.append({
                "type": "added",
                "path": current_path,
                "value": dict2[key]
            })

    return differences


# Contoh penggunaan
if __name__ == "__main__":
    dict_a = {
        "server": {
            "host": "192.168.1.1",
            "port": 8080,
            "ssl": True
        },
        "database": {
            "name": "prod_db",
            "user": "admin"
        }
    }

    dict_b = {
        "server": {
            "host": "192.168.1.2",  # Changed
            "port": 8080,
            "timeout": 30  # Added
        },
        "database": {
            "name": "prod_db",
            "user": "admin",
            "password": "secret"  # Added
        },
        "cache": {  # Added
            "enabled": True
        }
    }

    diffs = diff_dicts(dict_a, dict_b)

    print(f"Total differences: {len(diffs)}\n")
    for diff in diffs:
        if diff["type"] == "added":
            print(f"[+] Added: {diff['path']} = {diff['value']}")
        elif diff["type"] == "removed":
            print(f"[-] Removed: {diff['path']} = {diff['value']}")
        elif diff["type"] == "changed":
            print(f"[~] Changed: {diff['path']}: {diff['old_value']} → {diff['new_value']}")
```

